import { task, wait } from "@trigger.dev/sdk";

export const delayedNotify = task({
  id: "delayed-notify-${trial_id}",
  run: async (payload: { userId: string; message: string }) => {
    await wait.for({ seconds: 10 });
    return {
      sent: true,
      message: payload.message,
    };
  },
});

